const existingProductKeys = new Set(
  products.flatMap((p) => [p.id, p.slug, p.name.en.trim().toLowerCase()]),
);

for (const product of csvProductAdditions) {
  const keys = [product.id, product.slug, product.name.en.trim().toLowerCase()];
  if (keys.some((key) => existingProductKeys.has(key))) continue;
  products.push(product);
  keys.forEach((key) => existingProductKeys.add(key));
}

function toPsychologicalIqdPrice(amount: number) {
  if (amount <= 0 || amount % 1000 !== 0) return amount;

  const thousands = amount / 1000;
  if (thousands % 10 === 9) return amount;

  return Math.max(0, amount - 1000);
}

for (const product of products) {
  product.price = toPsychologicalIqdPrice(product.price);
  product.brand = normalizeBrandName(product.brand);

  if (product.compareAt) {
    const adjustedCompareAt = toPsychologicalIqdPrice(product.compareAt);
    product.compareAt = adjustedCompareAt > product.price ? adjustedCompareAt : product.compareAt;
  }
}

function normalizeBrandName(brand: string) {
  const key = brand.toLowerCase().replace(/[^a-z0-9]+/g, "");
  if (key === "7hz" || key === "7hertz") return "7hz";
  if (key === "moondrop") return "MOONDROP";
  return brand;
}

export const brandList: string[] = Array.from(new Set(products.map(p => p.brand).filter(Boolean))).sort();

export { formatPrice } from "@/lib/formatPrice";

